// ============================================
// LIMPIADOR DE JSON UNIVERSAL - AGENTE SANTIAGO
// ============================================
// Limpia y valida JSON del agente IA con flexibilidad total
// Acepta múltiples formatos y estructuras de entrada

// Obtener la respuesta del agente
const agentResponse = $input.first().json;

// ============================================
// FUNCIÓN PRINCIPAL DE LIMPIEZA
// ============================================
function cleanAndValidateJSON(response) {
  try {
    let jsonString = '';

    // ============================================
    // PASO 1: EXTRAER EL JSON STRING
    // ============================================
    if (response && response.output) {
      jsonString = typeof response.output === 'string' ? response.output : JSON.stringify(response.output);
    } else if (typeof response === 'object' && response !== null) {
      jsonString = JSON.stringify(response);
    } else if (typeof response === 'string') {
      jsonString = response;
    } else {
      throw new Error('Formato de respuesta inválido');
    }

    // ============================================
    // PASO 2: LIMPIAR CARACTERES Y FORMATO
    // ============================================

    // Remover BOM (Byte Order Mark)
    jsonString = jsonString.replace(/^\uFEFF/, '');

    // Remover caracteres de control invisibles
    jsonString = jsonString.replace(/[\u0000-\u0008\u000B-\u000C\u000E-\u001F\u007F-\u009F]/g, '');

    // Trim inicial
    jsonString = jsonString.trim();

    // Remover prefijos "json" o "json\n" antes de la llave
    jsonString = jsonString.replace(/^(json|JSON)\s*\n?\s*\{/, '{');

    // Buscar JSON dentro de bloques de código markdown
    const codeBlockMatch = jsonString.match(/```(?:json)?\s*(\{[\s\S]*?\})\s*```/);
    if (codeBlockMatch) {
      jsonString = codeBlockMatch[1].trim();
    }

    // Si el string está envuelto en comillas con escapes (ejemplo: "{\n  \"key\": \"value\"\n}")
    if (jsonString.startsWith('"') && jsonString.endsWith('"')) {
      try {
        jsonString = JSON.parse(jsonString);
      } catch (e) {
        jsonString = jsonString.slice(1, -1);
      }
    }

    // Buscar JSON entre otros textos (extraer solo el objeto JSON)
    const jsonMatch = jsonString.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      jsonString = jsonMatch[0];
    }

    // Remover comas finales antes de llaves o corchetes de cierre
    jsonString = jsonString.replace(/,(\s*[}\]])/g, '$1');

    // Normalizar comillas tipográficas
    jsonString = jsonString.replace(/[""]/g, '"');
    jsonString = jsonString.replace(/['']/g, "'");

    // ============================================
    // PASO 3: PARSEAR EL JSON
    // ============================================

    let parsedJSON;
    try {
      parsedJSON = JSON.parse(jsonString);
    } catch (parseError) {
      console.warn('Primer intento de parseo falló, intentando reparaciones...');

      // Intentar agregar comillas a claves sin comillas
      jsonString = jsonString.replace(/([{,]\s*)(\w+)(\s*:)/g, '$1"$2"$3');

      // Intentar corregir valores null sin comillas
      jsonString = jsonString.replace(/:\s*null\s*([,}])/g, ': null$1');

      // Reintentar parseo
      try {
        parsedJSON = JSON.parse(jsonString);
      } catch (secondError) {
        throw new Error(`No se pudo parsear el JSON: ${secondError.message}`);
      }
    }

    // ============================================
    // PASO 4: VALIDAR ESTRUCTURA (FLEXIBLE)
    // ============================================

    // Campo obligatorio: respuesta
    if (!('respuesta' in parsedJSON)) {
      throw new Error('Falta el campo obligatorio: respuesta');
    }

    // Validar que respuesta sea string no vacío
    if (typeof parsedJSON.respuesta !== 'string' || parsedJSON.respuesta.trim() === '') {
      throw new Error('El campo "respuesta" debe ser un string no vacío');
    }

    // ============================================
    // PASO 5: AGREGAR CAMPOS FALTANTES (SOLO LOS 4 REQUERIDOS)
    // ============================================

    // Solo los 4 campos del primer documento
    const camposRequeridos = {
      escalamiento: null,
      enviar_formulario: null,
      estado: null
    };

    // Agregar campos faltantes con valores por defecto
    Object.keys(camposRequeridos).forEach(campo => {
      if (!(campo in parsedJSON)) {
        parsedJSON[campo] = camposRequeridos[campo];
      }
    });

    // ============================================
    // PASO 6: NORMALIZAR VALORES ESPECÍFICOS
    // ============================================

    // Normalizar "escalamiento" (acepta: "escalamiento", "doble_respuesta", o null)
    const validEscalamiento = ['escalamiento', 'doble_respuesta', null];
    if (!validEscalamiento.includes(parsedJSON.escalamiento)) {
      console.warn(`Valor inválido en escalamiento: "${parsedJSON.escalamiento}". Se normalizará a null.`);
      parsedJSON.escalamiento = null;
    }

    // Normalizar "enviar_formulario" (solo acepta "enviar_plantilla" o null)
    if (parsedJSON.enviar_formulario !== null && parsedJSON.enviar_formulario !== 'enviar_plantilla') {
      console.warn(`Valor inválido en enviar_formulario: "${parsedJSON.enviar_formulario}". Se normalizará a null.`);
      parsedJSON.enviar_formulario = null;
    }

    // Normalizar "estado" (solo acepta "cerrado" o null)
    if (parsedJSON.estado !== null && parsedJSON.estado !== 'cerrado') {
      // Si el valor es "null" como string, convertir a null
      if (parsedJSON.estado === "null") {
        parsedJSON.estado = null;
      } else {
        console.warn(`Valor inválido en estado: "${parsedJSON.estado}". Se normalizará a null.`);
        parsedJSON.estado = null;
      }
    }

    // ============================================
    // PASO 7: LIMPIAR TEXTO DE RESPUESTA
    // ============================================

    parsedJSON.respuesta = parsedJSON.respuesta
      .replace(/\\n/g, '\n') // Convertir \n escapados a saltos reales
      .replace(/\n{3,}/g, '\n\n') // Máximo 2 saltos de línea consecutivos
      .trim();

    // ============================================
    // PASO 8: CREAR OBJETO DE SALIDA
    // ============================================

    return {
      respuesta: parsedJSON.respuesta,
      escalamiento: parsedJSON.escalamiento,
      enviar_formulario: parsedJSON.enviar_formulario,
      estado: parsedJSON.estado,
      _metadata: {
        success: true,
        cleaned: true,
        timestamp: new Date().toISOString(),
        cleaned_by: 'json_cleaner_universal'
      }
    };

  } catch (error) {
    // ============================================
    // MANEJO DE ERRORES
    // ============================================
    console.error('Error al limpiar JSON:', error.message);
    console.error('Respuesta original:', JSON.stringify(response, null, 2));

    // Retornar JSON de fallback
    return {
      respuesta: "Disculpa, tuve un problema técnico al procesar tu mensaje. ¿Podrías repetirlo por favor? 🙏",
      escalamiento: "escalamiento", // Escalar automáticamente en caso de error
