// Obtener los datos del nodo anterior
const inputData = $input.all();

// Obtener el mensaje del nodo "When Executed by Another Workflow"
const mensajeInicial = $('When Executed by Another Workflow').first().json.mensaje || '';

// Array para almacenar los resultados concatenados
const results = [];

// Procesar cada item del input
for (const item of inputData) {
  const data = item.json;

  // Si es un array, procesar cada elemento
  const records = Array.isArray(data) ? data : [data];

  for (const record of records) {
    let textoCompleto = "";

    // Agregar el mensaje inicial si existe (limpio, sin encabezado)
    if (mensajeInicial && mensajeInicial.trim() !== '') {
      textoCompleto += mensajeInicial.trim();
    }

    // Verificar si el registro es un error (contiene campos 'message' y 'error')
    const esError = record.hasOwnProperty('message') && record.hasOwnProperty('error');

    // Solo procesar información de queja si NO es un error
    if (!esError) {
      // Mapeo de nombres de campos a etiquetas más legibles
      const etiquetas = {
        'id': 'ID de Queja',
        'client_id': 'ID de Cliente',
        'fecha': 'Fecha',
        'cliente_nombre': 'Nombre del Cliente',
        'tipo_queja': 'Tipo de Queja',
        'nivel_urgencia': 'Nivel de Urgencia',
        'servicio_afectado': 'Servicio Afectado',
        'detalles': 'Detalles',
        'emocion_cliente': 'Emoción del Cliente',
        'escalacion_requerida': 'Requiere Escalación',
        'estado': 'Estado',
        'created_at': 'Fecha de Creación',
        'updated_at': 'Última Actualización',
        'formulario_enviado': 'Estado del Formulario'
      };

      // Contar campos válidos
      let camposValidos = 0;
      let contenidoQueja = "";

      // Iterar sobre todas las propiedades del objeto
      for (const [key, value] of Object.entries(record)) {
        // Saltar campos vacíos, null o undefined
        if (value === null || 
            value === undefined || 
            value === '' || 
            (typeof value === 'string' && value.trim() === '')) {
          continue;
        }

        camposValidos++;

        // Obtener la etiqueta legible o usar el nombre del campo
        const etiqueta = etiquetas[key] || key.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());

        // Formatear el valor según su tipo
        let valorFormateado = value;

        if (typeof value === 'boolean') {
          valorFormateado = value ? 'Sí' : 'No';
        } else if (typeof value === 'string' && value.includes('T') && value.includes('Z')) {
          // Formatear fechas
          try {
            const fecha = new Date(value);
            valorFormateado = fecha.toLocaleString('es-MX', { 
              timeZone: 'America/Mexico_City',
              dateStyle: 'full',
              timeStyle: 'short'
            });
          } catch (e) {
            valorFormateado = value;
          }
        } else if (typeof value === 'string') {
          valorFormateado = value.replace(/_/g, ' ');
        }

        contenidoQueja += `${etiqueta}: ${valorFormateado}\n`;
      }

      // Solo agregar la sección de información de queja si hay campos válidos
      if (camposValidos > 0) {
        // Agregar separador si ya hay mensaje del cliente
        if (textoCompleto.trim() !== '') {
          textoCompleto += "\n\n═══════════════════════════════════════\n\n";
        }
        textoCompleto += "INFORMACIÓN DE LA QUEJA:\n\n";
        textoCompleto += contenidoQueja;
        textoCompleto += "\n---\n";
      }
    }

    // Solo agregar al resultado si hay contenido (mensaje o campos de queja válidos)
    if (textoCompleto.trim() !== '') {
      results.push({
        json: {
          texto_concatenado: textoCompleto,
          datos_originales: record
        }
      });
    }
  }
}

return results;

